#!/usr/bin/env python3
"""
MKT Christ — 2 Kings chapters 15–17 (fill: verse-sparse chapters)
Run: python3 scripts/zc-christ-2kings-fill-15-17.py

Covers missing verses:
  ch15: v5 exists; fills v1–4, v6–38   (37 missing)
  ch16: v7 exists; fills v1–6, v8–20   (19 missing)
  ch17: v13 exists; fills v1–12, v14–41 (40 missing)

Christological focus:
  - ch15: Galilee/Naphtali taken (v29) → Matt 4:15-16 (Isa 9:1-2)
          Unstable dynasties → Christ as the eternal, unshakeable king
  - ch16: Ahaz's apostasy displaces the bronze altar → Heb 13:10 (true altar)
          Immanuel prophecy context; Christ vs. Ahaz's "son-and-servant" posture
  - ch17: Fall of Samaria + theological explanation → new covenant in Christ
          Samaritan syncretism → John 4; exile as curse → Gal 3:13
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

TWO_KINGS_CHRIST = {
    "15": {
        "1": "<p><span class='christ-shadow'>Azariah&#x2019;s accession synchronism opens a chapter of rapid dynastic turnover in the north. Amid the political instability — six northern kings in the compass of these verses, four by assassination — Christ stands as the contrast: &#x201C;Of the increase of his government and of peace there will be no end&#x201D; (Isa 9:7). Where Azariah&#x2019;s 52-year reign is the exception in a sea of instability, Christ&#x2019;s reign is the permanent eternal kingship that every human throne only approximates.</span></p>",
        "2": "<p><span class='christ-shadow'>Azariah reigns 52 years — the longest reign in Judah&#x2019;s history after Manasseh. Length of reign was a covenant blessing sign (Deut 17:20: the king who keeps the covenant will &#x201C;reign long over his kingdom, he and his children, in Israel&#x201D;). Christ&#x2019;s reign is not merely long but eternal — &#x201C;he will reign over the house of Jacob forever, and of his kingdom there will be no end&#x201D; (Luke 1:33). What earthly kings achieved by years, Christ possesses by nature.</span></p>",
        "3": "<p><span class='christ-shadow'>Azariah did right as his father Amaziah did. The partial Davidic pattern — doing right in broad terms — is the best most Judean kings achieve. Christ does not partially fulfill the covenant standard; he is &#x201C;holy, innocent, unstained, separated from sinners&#x201D; (Heb 7:26). The high place qualification in v4 marks Azariah&#x2019;s obedience as incomplete; Christ&#x2019;s obedience is complete and unqualified (Heb 5:8-9).</span></p>",
        "4": "<p><span class='christ-shadow'>The high places were not removed — the standard qualification that marks imperfect reform. No Judean king before Hezekiah removed the high places. This persistent worship outside Jerusalem (the divinely chosen place) typifies the problem of unauthorized approach to God. Christ removes the need for earthly sacred geography entirely: &#x201C;Believe me, the hour is coming when neither on this mountain nor in Jerusalem will you worship the Father&#x201D; (John 4:21). Christ is the end of the high-place problem — he himself is the meeting point.</span></p>",
        "6": "<p><span class='christ-shadow'>The regnal summary — Azariah&#x2019;s remaining acts recorded in the now-lost chronicles. The partial record of human achievement points toward the &#x201C;books&#x201D; that contain the full account of all deeds (Rev 20:12). But for those in Christ, another book matters more: &#x201C;The one who conquers will be clothed in white garments, and I will never blot his name out of the book of life&#x201D; (Rev 3:5). The royal chronicle records what earthly kings did; the book of life records those who are in Christ.</span></p>",
        "7": "<p><span class='christ-shadow'>Azariah buried in the city of David — the royal burial ground that marks Davidic legitimacy. Christ is the ultimate &#x201C;son of David&#x201D; (Matt 1:1) buried and raised from Jerusalem — not in a royal tomb but in a borrowed one (Matt 27:60), and not remaining there. His resurrection transformed the meaning of royal burial: &#x201C;He was not abandoned to Hades, nor did his flesh see corruption&#x201D; (Acts 2:31).</span></p>",
        "8": "<p><span class='christ-shadow'>Zechariah son of Jeroboam reigns six months — the shortest reign of any king in Kings except Zimri&#x2019;s seven days. The extreme brevity of Zechariah&#x2019;s reign closes the Jehu dynasty precisely at the fourth generation (Jehu → Jehoahaz → Joash → Jeroboam II → Zechariah), fulfilling the divine promise of 10:30. Christ ends all dynasties: &#x201C;he must reign until he has put all his enemies under his feet&#x201D; (1 Cor 15:25). Every human dynasty is temporary; his is not.</span></p>",
        "9": "<p><span class='christ-shadow'>Zechariah did not depart from the sins of Jeroboam. The &#x201C;sins of Jeroboam&#x201D; formula appears repeatedly in ch15 — it is the structural sin of the Northern Kingdom, entrenched through generations. What no Israelite king could break — the pull of Jeroboam&#x2019;s calves — Christ breaks definitively: he is the true object of worship that all false substitutes distort. The sin of worshiping a wrong image is ended by the &#x201C;image of the invisible God&#x201D; (Col 1:15) who is the true icon of the Father.</span></p>",
        "10": "<p><span class='christ-shadow'>Shallum conspires against Zechariah, strikes him down, and reigns. The cycle of violent succession in the north — assassination as the primary mode of regime change after the Jehu dynasty — is the antithesis of the Davidic covenant&#x2019;s promise of dynastic continuity. Christ is the king who comes to power not through assassination but through willing self-sacrifice: &#x201C;No one takes my life from me, but I lay it down of my own accord&#x201D; (John 10:18).</span></p>",
        "11": "<p><span class='christ-shadow'>The summary notice for Zechariah. The brevity of the notice reflects the brevity of the reign. Against the chaos of six-month reigns and assassinations, the promise of Ps 2:6-7 stands: &#x201C;As for me, I have set my King on Zion, my holy hill. I will tell of the decree: The LORD said to me, &#x2018;You are my Son; today I have begotten you.&#x2019;&#x201D; What the northern kings could not secure by force or lineage, Christ holds by eternal decree.</span></p>",
        "12": "<p><span class='christ-direct'>The fulfillment of YHWH&#x2019;s word to Jehu: &#x201C;your sons to the fourth generation shall sit on the throne of Israel&#x201D; (10:30) — &#x201C;this is the word of the LORD that he spoke to Jehu.&#x201D; The pattern of divine word → precise historical fulfillment is the grammar of redemptive history. Christ is the fullest instance of this pattern: &#x201C;All the promises of God find their Yes in him&#x201D; (2 Cor 1:20). Not one word of the LORD falls to the ground (2 Kings 10:10) — fulfilled here in Zechariah, fulfilled ultimately in Christ.</span></p>",
        "13": "<p><span class='christ-shadow'>Shallum reigns one month and is killed by Menahem. The one-month reign is even shorter than Zechariah&#x2019;s six months. The instability of earthly power — achieved by violence, lost by violence — is one of Scripture&#x2019;s recurring demonstrations that human kingship requires divine grounding. Christ&#x2019;s kingdom &#x201C;cannot be shaken&#x201D; (Heb 12:28) — it is established not by human conspiracy but by resurrection from the dead.</span></p>",
        "14": "<p><span class='christ-shadow'>Menahem kills Shallum and becomes king. Each assassination creates a new would-be dynasty, none of which lasts. The perpetual instability of the northern monarchy — twelve kings in approximately two centuries, many killed by successors — is the political expression of covenant breakdown. Christ brings the new covenant whose political expression is the eternal, unassailable kingdom: &#x201C;the kingdom of God is at hand&#x201D; (Mark 1:15), and it does not pass from one assassin to the next.</span></p>",
        "15": "<p><span class='christ-shadow'>Shallum&#x2019;s summary — his conspiracy recorded in now-lost chronicles. The chronicle records political facts; what matters covenantally is whether the king served YHWH. Shallum&#x2019;s conspiracy was politically successful for one month and then destroyed him. Christ warns against exactly this strategy: &#x201C;For what does it profit a man to gain the whole world and forfeit his soul?&#x201D; (Mark 8:36). The chronicles of earthly kings record gains measured in months; Christ&#x2019;s kingdom measures in eternity.</span></p>",
        "16": "<p><span class='christ-shadow'>Menahem&#x2019;s brutal act against Tiphsah — ripping open pregnant women of those who would not open their gates. The atrocity against vulnerable life is one of the most disturbing acts recorded in Kings, paralleling Elisha&#x2019;s Aramean vision (8:12). Christ is the protector of the vulnerable — &#x201C;blessed are the poor in spirit, for theirs is the kingdom of heaven&#x201D; (Matt 5:3) — and the one who calls for judgment on those who harm &#x201C;one of these little ones&#x201D; (Matt 18:6). The violence of Menahem&#x2019;s military power is the anti-type of Christ&#x2019;s kingdom.</span></p>",
        "17": "<p><span class='christ-shadow'>Menahem reigns ten years in Samaria — a relatively stable reign achieved by tribute payments to Assyria. The stability is purchased at the cost of vassalage: Menahem becomes a client king of Assyria. Christ refuses this kind of Satanic kingship offer: &#x201C;All these I will give you, if you will fall down and worship me&#x201D; — to which Jesus answers: &#x201C;Worship the Lord your God and serve him only&#x201D; (Matt 4:9-10). Menahem buys his throne by bowing to Pul; Christ refuses to buy his kingdom through cosmic capitulation.</span></p>",
        "18": "<p><span class='christ-shadow'>Menahem did evil — the sins of Jeroboam not departed from. The repeated formula in this chapter (vv9, 18, 24, 28) is not mere literary repetition but theological insistence: the northern kings are structurally embedded in Jeroboam&#x2019;s apostasy and cannot escape it. Only Christ breaks the power of entrenched sin: &#x201C;For sin will have no dominion over you, since you are not under law but under grace&#x201D; (Rom 6:14). What the northern kings could not break free of — Jeroboam&#x2019;s gravity — the gospel dismantles through union with Christ.</span></p>",
        "19": "<p><span class='christ-shadow'>Pul (Tiglath-Pileser III) invades and Menahem pays 1,000 talents of silver for Assyrian support. The tribute relationship — paying for protection — typifies the conditional security of earthly kingdoms that rely on foreign power. Christ offers unconditional security: &#x201C;Who shall separate us from the love of Christ? Shall tribulation, or distress, or persecution, or famine, or nakedness, or danger, or sword?&#x201D; (Rom 8:35). No tribute required; no foreign power needed; the kingdom Christ secures cannot be purchased away.</span></p>",
        "20": "<p><span class='christ-shadow'>The silver comes from a levy on wealthy Israelites — fifty shekels each. The taxation to fund a tribute payment to a foreign oppressor is Israel&#x2019;s tribute-from-the-weak-to-pay-the-strong pattern. Christ reverses this: he pays the ultimate tribute (his own life) so that his people are set free from all such payments. &#x201C;You were bought with a price; do not become slaves of men&#x201D; (1 Cor 7:23). The fifty-shekel levy on ordinary Israelites is the type; Christ&#x2019;s self-giving is the antitype that ends all debt.</span></p>",
        "21": "<p><span class='christ-shadow'>Menahem&#x2019;s regnal summary — his remaining acts in the now-lost chronicles. The record of a reign that purchased stability by subordination to Assyria is a portrait of the failure of self-protective power. Christ&#x2019;s power is demonstrated in weakness: &#x201C;When I am weak, then I am strong&#x201D; (2 Cor 12:10). The strategy of Menahem (buy protection) and the strategy of Christ (give yourself) are the two poles of the power question.</span></p>",
        "22": "<p><span class='christ-shadow'>Menahem rests and his son Pekahiah succeeds him. Dynastic succession — father to son — is the ordinary means of royal continuity. The Davidic dynasty&#x2019;s stability contrasts with the northern pattern; and Christ is the final Davidic Son: &#x201C;The LORD God will give him the throne of his father David, and he will reign over the house of Jacob forever&#x201D; (Luke 1:32-33). The father-son succession of earthly kings is a pale reflection of the eternal Father-Son relationship within which Christ&#x2019;s kingship is grounded.</span></p>",
        "23": "<p><span class='christ-shadow'>Pekahiah&#x2019;s two-year reign. The brevity again — a reign barely begun before assassination. The instability of the northern monarchy in its final decades (c. 742–722 BCE) mirrors the spiritual chaos of a people who have &#x201C;forgotten the Lord&#x2019;s works&#x201D; (Ps 78:11) and rejected his covenant. Christ comes as the fulfillment precisely into this chaos: &#x201C;He came to his own, and his own people did not receive him&#x201D; (John 1:11) — but his kingdom, unlike Pekahiah&#x2019;s, cannot be cut short.</span></p>",
        "24": "<p><span class='christ-shadow'>Pekahiah did evil — sins of Jeroboam continued. The unbroken series of &#x201C;did not depart from the sins of Jeroboam&#x201D; through chs 15-17 reads like a tragic chorus: no king of Israel ever broke free. But what no king could accomplish, Christ accomplishes: &#x201C;Since therefore Christ suffered in the flesh, arm yourselves with the same way of thinking, for whoever has suffered in the flesh has ceased from sin&#x201D; (1 Pet 4:1). The break from entrenched sin comes through death and resurrection — which is precisely what Christ provides.</span></p>",
        "25": "<p><span class='christ-shadow'>Pekah assassinates Pekahiah with fifty Gileadite warriors. The military overthrow in the throne room — men who served become killers of their master — inverts the royal protection that kings are supposed to provide. Christ&#x2019;s betrayal follows a similar pattern: &#x201C;He came to his own.&#x201D; But where Pekahiah dies as a powerless victim, Christ dies as the willing shepherd: &#x201C;The good shepherd lays down his life for the sheep&#x201D; (John 10:11).</span></p>",
        "26": "<p><span class='christ-shadow'>Pekahiah&#x2019;s summary. The record of another failed reign — evil perpetuated, killed by a subordinate — adds to the accumulating evidence that the northern monarchy is in terminal decline. The full picture of Israel&#x2019;s kings in ch15 is a portrait of systemic failure, which makes Christ&#x2019;s kingship not an extension of this pattern but its radical cure.</span></p>",
        "27": "<p><span class='christ-shadow'>Pekah reigns twenty years — by northern standards a long reign. His alliance with Rezin of Syria (the Syro-Ephraimite coalition of vv37, 16:5) will precipitate the crisis that generates Isaiah&#x2019;s Immanuel prophecy (Isa 7:14). Christ is the Immanuel born in response to that crisis: the sign given to Ahaz is fulfilled not in Pekah&#x2019;s lifetime but in the fullness of time (Gal 4:4) when &#x201C;the virgin shall conceive and bear a son and shall call his name Immanuel&#x201D; (Isa 7:14; Matt 1:23).</span></p>",
        "28": "<p><span class='christ-shadow'>Pekah did not depart from Jeroboam&#x2019;s sins. The penultimate northern king continues the cycle. The persistence of national sin through generations demonstrates that covenant obedience cannot be produced by human effort or royal example alone. The new covenant addresses this root: &#x201C;I will put my law within them and write it on their hearts&#x201D; (Jer 31:33) — the internalization of Torah through the Spirit that Christ sends fulfills what no northern king could achieve externally.</span></p>",
        "29": "<p><span class='christ-direct'>Tiglath-Pileser takes Galilee and Naphtali. This is the historical event that Isaiah 9:1-2 addresses: &#x201C;In the former time he brought into contempt the land of Zebulun and Naphtali, but in the latter time he has made it glorious, the way of the sea, beyond the Jordan, Galilee of the nations.&#x201D; Matthew 4:15-16 quotes Isaiah 9:1-2 directly to frame the beginning of Jesus&#x2019;s Galilean ministry: &#x201C;The people dwelling in darkness have seen a great light.&#x201D; The territory reduced to darkness by Tiglath-Pileser&#x2019;s conquest in 2 Kings 15:29 becomes the specific region of the dawning light of Christ&#x2019;s ministry.</span></p>",
        "30": "<p><span class='christ-shadow'>Hoshea assassinates Pekah — the last northern king comes to power through the same violent means as his predecessors. The cycle of regicide ends only with the external force of Assyria ending the northern monarchy altogether. No king from within Israel could reform the system; the system had to end. Christ does not reform the old covenant system — he fulfills and supersedes it: &#x201C;The law was given through Moses; grace and truth came through Jesus Christ&#x201D; (John 1:17).</span></p>",
        "31": "<p><span class='christ-shadow'>Pekah&#x2019;s summary. Nine kings of Israel have been noted in ch15; only one (Zechariah) ends the dynasty as promised. The rest are assassinated or die in obscurity. The political tragedy of ch15 is also a spiritual tragedy: &#x201C;They did not cry to me from the heart when they wailed upon their beds&#x201D; (Hos 7:14). What was missing — true repentance, genuine return — is what Christ produces through his Spirit in those who are his.</span></p>",
        "32": "<p><span class='christ-shadow'>Jotham son of Uzziah becomes king of Judah. The parallelism of northern chaos and southern continuity throughout the chapter is striking: while six kings succeed each other violently in Samaria, Judah has one king through most of the same period. The Davidic dynasty&#x2019;s greater stability is an anticipation of the eternal Davidic throne Christ occupies. Not every Judean king is good, but the line continues; not every northern king is evil, but the line collapses.</span></p>",
        "33": "<p><span class='christ-shadow'>Jotham: 25 years old, reigns 16 years. The regnal formula locates him precisely in historical time. Christ&#x2019;s incarnation is similarly time-precise: &#x201C;But when the fullness of time had come, God sent forth his Son&#x201D; (Gal 4:4). The specificity of biblical chronology — kings, years, synchronisms — grounds redemptive history in real time. Christ does not enter myth but history, just as Jotham enters history with a specific age and reign-length.</span></p>",
        "34": "<p><span class='christ-shadow'>Jotham did right as his father Uzziah had done — another qualified positive evaluation. The chain of partial faithfulness (Uzziah → Jotham, both right but with qualifications) shows how the best human kings can only partially fulfill the covenant ideal. Christ is the unqualified fulfillment: every positive evaluation of Israel&#x2019;s kings is &#x201C;right in the eyes of the LORD, except...&#x201D;; Christ is right without exception, the only king who meets the Deuteronomic standard completely.</span></p>",
        "35": "<p><span class='christ-shadow'>High places not removed — Jotham builds the upper gate of the temple. The combination of partial faithfulness and partial failure characterizes Jotham exactly as it does his father. But Christ builds a greater temple through a greater faithfulness: &#x201C;I will build my church, and the gates of hell shall not prevail against it&#x201D; (Matt 16:18). Jotham&#x2019;s upper gate is a building project; Christ&#x2019;s church is a living structure of people &#x201C;built on the foundation of the apostles and prophets, Christ Jesus himself being the cornerstone&#x201D; (Eph 2:20).</span></p>",
        "36": "<p><span class='christ-shadow'>Jotham&#x2019;s regnal summary. The accumulation of these summary notices — kings who reigned and passed — points forward to the one who does not simply reign and pass. Ps 45:6: &#x201C;Your throne, O God, is forever and ever&#x201D; — addressed to the king, ultimately fulfilled only in Christ. The summary notices of ch15 are the foil against which the eternal throne of Ps 45 stands out.</span></p>",
        "37": "<p><span class='christ-direct'>In those days YHWH begins to send Rezin and Pekah against Judah — the Syro-Ephraimite coalition that will threaten Ahaz and generate Isaiah&#x2019;s Immanuel prophecy (Isa 7:1-17). The divine sovereignty over geopolitical events (&#x201C;YHWH began to send&#x201D;) frames the Assyrian threat as providential. Matthew&#x2019;s Gospel repeatedly uses the same framing: &#x201C;This took place to fulfill what was spoken by the prophet&#x201D;. The crisis of ch15:37 is the providential occasion for the greatest messianic prophecy of Isaiah&#x2019;s book, fulfilled in Christ.</span></p>",
        "38": "<p><span class='christ-shadow'>Jotham buried in the city of David; Ahaz succeeds him. The peaceful dynastic transfer — father to son without assassination, unusual by northern standards — continues in Judah. Ahaz will be the worst of Judah&#x2019;s kings in this era, but the line continues. The Davidic dynasty persists through good kings and bad because the covenant with David is not based on the individual king&#x2019;s merit: &#x201C;For the sake of David my servant I will not tear away all the kingdom&#x201D; (1 Kings 11:13). This same covenant-fidelity reaches its fullest expression in the one who is both son of David and the eternal Son of God.</span></p>"
    },
    "16": {
        "1": "<p><span class='christ-shadow'>Ahaz&#x2019;s accession — a king who will prove the most unfaithful of Judah&#x2019;s dynasty in this generation. The reign of Ahaz is the context for Isaiah&#x2019;s Immanuel prophecy (Isa 7): a king who refuses the divine sign is told that God will give his own sign — the virgin-born child. Ahaz&#x2019;s refusal of trust sets the scene for the announcement of the one who will himself be Immanuel, &#x201C;God with us&#x201D; (Matt 1:23).</span></p>",
        "2": "<p><span class='christ-shadow'>Ahaz&#x2019;s evaluation: he did not do right as David his father did. The explicit Davidic comparison inverted — Ahaz failed the standard that David set. Christ is the positive fulfillment of what Ahaz negated: &#x201C;He has raised up a horn of salvation for us in the house of his servant David&#x201D; (Luke 1:69). Ahaz is a dark foil that makes the promised Davidic son all the more necessary.</span></p>",
        "3": "<p><span class='christ-direct'>Ahaz walked in the ways of the kings of Israel and made his son pass through fire. The child sacrifice — <i>he'evir beno ba-esh</i> — is the nadir of royal apostasy. The God of Israel requires not the death of children but rather offers his own Son: &#x201C;For God so loved the world that he gave his only Son&#x201D; (John 3:16). The contrast between Molech-worship (requiring the sacrifice of sons) and the gospel (God sacrificing his Son so that human sons and daughters might live) is one of the deepest contrasts in Scripture.</span></p>",
        "4": "<p><span class='christ-shadow'>Sacrifices at high places, on hills, under every spreading tree. The dispersal of worship — everywhere except the divinely designated place — is the opposite of true covenant worship. Christ centralized worship not to a building but to himself: &#x201C;The Father seeks those who worship him in spirit and truth&#x201D; (John 4:23). Ahaz scattered worship across every hilltop; Christ draws all true worship to the one person of the Son.</span></p>",
        "5": "<p><span class='christ-direct'>Rezin and Pekah besiege Jerusalem but cannot take it. The inability of the Syro-Ephraimite coalition to conquer the city is the context for Isaiah&#x2019;s &#x201C;this one too will not succeed, for God is with us&#x201D; (Isa 8:10 — <i>Immanuel</i>). The siege that fails despite Israel&#x2019;s internal apostasy points to Christ&#x2019;s promise: &#x201C;I will build my church, and the gates of hell shall not prevail against it&#x201D; (Matt 16:18). What Rezin and Pekah failed to do — destroy Jerusalem — Babylon would later accomplish as judgment; but Christ&#x2019;s church cannot be destroyed by any coalition.</span></p>",
        "6": "<p><span class='christ-shadow'>Rezin recovers Elath for Syria — Judah loses a strategic port. The progressive narrowing of Judah&#x2019;s territory under Ahaz is the covenant curse of Deuteronomy actualized. What kings lose through unfaithfulness, Christ restores through the inheritance of the new creation: &#x201C;Blessed are the meek, for they shall inherit the earth&#x201D; (Matt 5:5). The territory lost by Ahaz&#x2019;s faithlessness is the type; the inheritance secured by Christ&#x2019;s perfect faithfulness is the antitype.</span></p>",
        "8": "<p><span class='christ-shadow'>Ahaz takes silver and gold from the temple and royal treasury to send to Tiglath-Pileser. The despoliation of the temple — stripping the sacred treasury to bribe a foreign king — is the opposite of the Magi&#x2019;s offering: three wise men bring gold, frankincense, and myrrh to the true king (Matt 2:11), while Ahaz sends gold from the LORD&#x2019;s treasury to a human overlord. One movement directs wealth toward the true king; the other strips the sacred to serve the worldly.</span></p>",
        "9": "<p><span class='christ-shadow'>Tiglath-Pileser captures Damascus and kills Rezin — the Assyrian king serves as the rod of God&#x2019;s anger (Isa 10:5) against Ahaz&#x2019;s enemies. The double irony: Ahaz buys Assyrian help against Aram, but the help that saves him from one enemy will eventually enslave Judah to Assyria itself. The short-term relief purchased by apostasy has long-term destructive consequences. Christ offers permanent security through his own sacrifice — no short-term bargain with destructive consequences.</span></p>",
        "10": "<p><span class='christ-shadow'>Ahaz sees a Damascus altar and sends its pattern to Urijah the priest to replicate in Jerusalem. The importation of a pagan altar design into the temple — replacing Solomon&#x2019;s bronze altar with a Syrian model — is a reversal of the temple&#x2019;s entire purpose. The temple was built to draw the nations toward YHWH (1 Kings 8:41-43); Ahaz allows pagan religious aesthetics to flow in the opposite direction, into Jerusalem. Christ cleanses the temple (John 2:13-22) and announces that his body is the true temple — which no foreign design can corrupt.</span></p>",
        "11": "<p><span class='christ-shadow'>Urijah the priest builds the Damascus altar exactly as Ahaz specified. The priest who complies with the king&#x2019;s pagan order — the corruption of the priestly office by royal command — is the opposite of the priesthood Christ embodies. Christ is the high priest who serves not at a king&#x2019;s command but at the Father&#x2019;s will: &#x201C;We have such a high priest, one who is seated at the right hand of the throne of the Majesty in heaven&#x201D; (Heb 8:1). The corrupted earthly priest who built the Damascus altar is replaced by the uncorrupted heavenly priest.</span></p>",
        "12": "<p><span class='christ-shadow'>Ahaz mounts his new altar and offers on it. The king usurping priestly functions — approaching the altar himself — recalls Uzziah&#x2019;s attempt to burn incense (2 Chr 26:16-20) which brought leprosy. But where Uzziah&#x2019;s usurpation of priestly roles was condemned, Christ legitimately combines both offices: he is &#x201C;a priest forever after the order of Melchizedek&#x201D; (Ps 110:4; Heb 7:17) and the royal Son. The royal-priestly combination that sinful kings attempted illegitimately, Christ holds by divine appointment.</span></p>",
        "13": "<p><span class='christ-shadow'>Ahaz offers burnt offerings, grain offerings, drink offerings, and peace offerings on the Damascus altar. All the categories of Levitical sacrifice performed on a pagan-designed altar — the content is formally correct but the object and location are corrupted. Christ fulfills all these offerings in his one self-offering: &#x201C;He has no need to offer sacrifices daily&#x2122; for this he did once for all when he offered up himself&#x201D; (Heb 7:27). The burnt offering (total consecration), the grain offering (dedication of life), the drink offering (poured out), the peace offering (reconciliation) — all are fulfilled in Christ&#x2019;s one sacrifice.</span></p>",
        "14": "<p><span class='christ-type'>Ahaz moves Solomon&#x2019;s bronze altar — the altar of the LORD that stood before the temple — to the side, repositioning it as a secondary place for his own divination. The displacement of the bronze altar (where the great sacrifices were offered) by the Syrian replica is a demotion of the divinely ordained worship system. Christ is the true altar (Heb 13:10: &#x201C;We have an altar from which those who serve the tent have no right to eat&#x201D;) — the one legitimate sacrifice-place that Ahaz&#x2019;s Syrian altar displaced and Christ restores.</span></p>",
        "15": "<p><span class='christ-shadow'>Ahaz&#x2019;s instructions to Urijah: use the great altar for all the prescribed offerings; the bronze altar is for the king&#x2019;s private divination. The further degradation — Solomon&#x2019;s altar demoted to a vehicle for royal divination — reveals how completely Ahaz has severed worship from covenant. Christ reconsecrates worship to its true purpose: &#x201C;God is spirit, and those who worship him must worship in spirit and truth&#x201D; (John 4:24). The divination-oriented worship of Ahaz is the antithesis of Spirit-directed worship in truth.</span></p>",
        "16": "<p><span class='christ-shadow'>Urijah the priest does everything Ahaz commanded. The unreserved priestly compliance with royal apostasy is the failure of the prophetic/priestly office. Contrast Christ, the prophet who speaks only what the Father gives him (John 12:49-50) and who refuses to comply with the demands of earthly authorities when they conflict with the Father&#x2019;s will (Acts 5:29 principle: obey God rather than men). The faithful priest does not simply execute royal commands; Christ the faithful priest executes only the Father&#x2019;s will.</span></p>",
        "17": "<p><span class='christ-shadow'>Ahaz cuts the side panels of the wheeled stands and lifts the bronze sea from the stone oxen, setting it on a stone pavement. The systematic dismantling of Solomon&#x2019;s temple furnishings — the sea, the stands, the bases — is reverse-creation: what took years to build is stripped in a reign. Christ announces the end of the temple system, but not through desecration — through fulfillment: &#x201C;Destroy this temple, and in three days I will raise it up&#x201D; (John 2:19). The dismantling Ahaz did through apostasy, Christ transforms through resurrection.</span></p>",
        "18": "<p><span class='christ-shadow'>Ahaz removes the covered Sabbath walkway and changes the royal entrance — modifications &#x201C;because of the king of Assyria.&#x201D; Architecture altered to please a foreign overlord — the temple&#x2019;s layout changed to accommodate Tiglath-Pileser&#x2019;s protocol. Christ does not modify his Father&#x2019;s house to accommodate earthly powers: &#x201C;My house shall be called a house of prayer, but you make it a den of robbers&#x201D; (Matt 21:13). Ahaz reshapes the temple for Assyrian approval; Christ cleanses it for the Father&#x2019;s glory.</span></p>",
        "19": "<p><span class='christ-shadow'>Ahaz&#x2019;s regnal summary. The chronicle of Ahaz&#x2019;s reign is a catalog of faithful-covenant subversion: child sacrifice, high places, Syrian altar, temple stripping, architectural modification for Assyria. Against this portrait of comprehensive apostasy, the Immanuel promise stands as a divine counter-offer. God did not abandon his covenant when Ahaz abandoned it; he gave a sign: the virgin will conceive. The promise comes precisely when the human king most thoroughly fails.</span></p>",
        "20": "<p><span class='christ-shadow'>Ahaz dies and Hezekiah his son reigns — the great reformer follows the greatest apostate. The dynastic continuity that produces a Hezekiah after an Ahaz is itself covenant grace: YHWH preserves the Davidic line even through the worst of its kings. The patience of God that allows an Ahaz to be succeeded by a Hezekiah is the patience that &#x201C;is not slow to fulfill his promise but is patient toward you, not wishing that any should perish&#x201D; (2 Pet 3:9). The Davidic dynasty surviving Ahaz&#x2019;s apostasy is the type of grace that persists through human failure.</span></p>"
    },
    "17": {
        "1": "<p><span class='christ-shadow'>Hoshea&#x2019;s accession — the last king of Israel. The Northern Kingdom&#x2019;s final king reigns nine years (c. 732–722 BCE) before Samaria falls. The end of the Israelite monarchy in the north is the terminus of a two-century experiment in covenant-defined kingship that repeatedly failed. Christ comes as the fulfillment of everything that Israelite kingship pointed toward but never achieved: the king who perfectly serves YHWH, perfectly protects the people, and reigns forever.</span></p>",
        "2": "<p><span class='christ-shadow'>Hoshea did evil — but not like the kings of Israel before him. The qualified condemnation is unusual; perhaps Hoshea showed some minimal improvement. But &#x201C;not as evil as others&#x201D; is still evil. Against a standard of perfection, partial improvement is insufficient. Christ&#x2019;s righteousness is not &#x201C;better than&#x201D; but &#x201C;complete&#x201D; — &#x201C;the righteousness of God through faith in Jesus Christ for all who believe&#x201D; (Rom 3:22). The comparison standard is not other kings but God&#x2019;s own holiness.</span></p>",
        "3": "<p><span class='christ-shadow'>Shalmaneser (V) marches against Hoshea, who becomes his vassal. The submission to Assyrian power — paying tribute, becoming a dependent client — is the final humiliation before the deportation. What Menahem purchased (Assyrian protection for tribute), Hoshea inherits and then tries to escape (v4). The cycle of tribute-and-dependency is what Christ breaks: &#x201C;For freedom Christ has set us free; stand firm therefore, and do not submit again to a yoke of slavery&#x201D; (Gal 5:1).</span></p>",
        "4": "<p><span class='christ-shadow'>Hoshea&#x2019;s conspiracy — sending envoys to Egypt (&#x201C;So king of Egypt&#x201D; is uncertain; perhaps Sibe/Osorkon IV) and withholding tribute. The double-dealing that gets Hoshea imprisoned is the northern equivalent of trusting in Egypt rather than YHWH (Isa 31:1-3). The prophet Isaiah repeatedly condemns reliance on Egypt&#x2019;s military: &#x201C;The Egyptians are man and not God, and their horses are flesh and not spirit&#x201D; (Isa 31:3). Christ is the one on whom trust is rightly placed — not flesh and not spirit in that sense, but the incarnate Word who is both human and divine.</span></p>",
        "5": "<p><span class='christ-shadow'>Three-year siege of Samaria. The prolonged siege — years of suffering before the final capitulation — is the covenant judgment for Israel&#x2019;s sustained rejection of YHWH over generations. Against the patience of the siege image, Christ&#x2019;s parables of patient waiting resonate: the father who ran to meet the returning son had waited long (Luke 15:20). But the siege also pictures the finality of judgment when it comes: &#x201C;He who is unjust, let him be unjust still&#x201D; (Rev 22:11). The time for repentance had passed; the siege closed.</span></p>",
        "6": "<p><span class='christ-shadow'>Samaria falls; Israel deported to Halah, Habor, and Median cities. The exile is the ultimate covenant curse — loss of land, loss of temple, loss of national identity. Yet it is also the context for some of the richest messianic prophecy: Isaiah 40-55 (written to address the exile) is saturated with prophecy of the servant who would bear Israel&#x2019;s iniquities. The Babylonian exile of Judah will produce the same effect: loss becomes the womb of promise. Christ bears the ultimate exile (&#x201C;My God, my God, why have you forsaken me?&#x201D; — Matt 27:46) so that his people need not be permanently exiled from God.</span></p>",
        "7": "<p><span class='christ-direct'>The Deuteronomistic theological explanation begins: &#x201C;This happened because the Israelites had sinned against the LORD their God.&#x201D; The theological interpretation of historical events is the Deuteronomist&#x2019;s distinctive contribution — not merely recording what happened but why. Christ&#x2019;s cross is the ultimate interpretive event: &#x201C;For Christ died for sins once for all, the righteous for the unrighteous, to bring you to God&#x201D; (1 Pet 3:18). The &#x201C;this happened because&#x201D; logic of Deuteronomistic history reaches its apex at Calvary, where the &#x201C;why&#x201D; is the accumulated sin of all humanity.</span></p>",
        "8": "<p><span class='christ-shadow'>They followed the practices of the nations the LORD had expelled and of their own kings. The double source of contamination — pagan nations and apostate kings — created a feedback loop of covenant violation. The law that was supposed to set Israel apart (Deut 4:6-8: &#x201C;your wisdom in the sight of the peoples&#x201D;) was abandoned in favor of imitation of the expelled nations. Christ restores the holy-nation identity: &#x201C;You are a chosen race, a royal priesthood, a holy nation&#x201D; (1 Pet 2:9) — the identity Israel was called to be but failed to maintain.</span></p>",
        "9": "<p><span class='christ-shadow'>The Israelites secretly did things not right — high places from watchtower to fortified city. The secrecy of their apostasy (&#x201C;secretly&#x201D; — <i>be-seter</i>) reveals guilt-consciousness: they knew what they were doing was wrong. This inner knowledge of wrongdoing is what Paul describes as the witness of conscience (Rom 2:15: &#x201C;they show that the work of the law is written on their hearts, their conscience bearing witness&#x201D;). The secret sin that conscience knows is precisely what Christ&#x2019;s atonement addresses at its deepest level.</span></p>",
        "10": "<p><span class='christ-shadow'>Sacred pillars and Asherah poles on every high hill and under every green tree. The proliferation of worship sites is the spatial expression of the broken covenant — worship scattered everywhere instead of concentrated at the divine meeting point. Christ draws all worship to himself as the single true altar and sanctuary: &#x201C;When I am lifted up from the earth, I will draw all people to myself&#x201D; (John 12:32). The scattered-everywhere worship of the high places finds its answer in the crucified, raised Christ who becomes the universal center of true worship.</span></p>",
        "11": "<p><span class='christ-shadow'>Incense burned at high places as the nations did — whom YHWH expelled. The worship Israel does is described as mimicking expelled nations whose worship God rejected. The irony is double: Israel worships like the nations; the nations are expelled for this worship; therefore Israel earns the same expulsion. But Christ breaks this cycle: &#x201C;He has abolished the law of commandments expressed in ordinances, that he might create in himself one new man in place of the two, so making peace&#x201D; (Eph 2:15). In Christ, Gentile and Jew together worship rightly.</span></p>",
        "12": "<p><span class='christ-shadow'>They served idols despite the explicit divine prohibition. The willful violation of clear command — &#x201C;You must not do this&#x201D; — is the classic definition of sin as transgression. Christ bears the condemnation of this transgression: &#x201C;He himself bore our sins in his body on the tree&#x201D; (1 Pet 2:24). The idol-worship explicitly prohibited in the first commandment is precisely what required the atoning work that Christ performs at the cross.</span></p>",
        "14": "<p><span class='christ-shadow'>They would not listen — as stubborn as their ancestors who did not trust YHWH. The ancestral pattern of hardness of heart becomes Israel&#x2019;s inheritance. Jesus describes the same pattern to his generation: &#x201C;You stiff-necked people, uncircumcised in heart and ears, you always resist the Holy Spirit. As your fathers did, so do you&#x201D; (Acts 7:51, Stephen&#x2019;s speech). The hardness of heart that led to Israel&#x2019;s exile is the same hardness that leads to the rejection of Christ — and what breaks it is not better teaching but heart-surgery: &#x201C;I will give you a new heart&#x201D; (Ezek 36:26).</span></p>",
        "15": "<p><span class='christ-shadow'>They rejected the covenant, pursued vanity (<i>hevel</i>), and became vain themselves — imitating the idols. The word <i>hevel</i> (vanity/breath) is the key term of Ecclesiastes: life oriented around things that are not God becomes as insubstantial as breath. &#x201C;Those who make idols are like them; so are all who trust in them&#x201D; (Ps 115:8). Those who imitate empty things become empty; those who are united to Christ are transformed into his image: &#x201C;We all, with unveiled face, beholding the glory of the Lord, are being transformed into the same image&#x201D; (2 Cor 3:18).</span></p>",
        "16": "<p><span class='christ-shadow'>They cast two metal calves, made an Asherah, worshipped the host of heaven, and served Baal. The full catalog of northern apostasy: Jeroboam&#x2019;s calves, Canaanite fertility religion, astral worship, Baal. Each false object of worship is a distortion of what is rightly sought in God alone. Christ is &#x201C;the image of the invisible God, the firstborn of all creation&#x201D; (Col 1:15) — the true visible form of the God who cannot be captured in calves or pillars. Every idol is a failed attempt to have what only Christ provides: access to the living God through a visible mediator.</span></p>",
        "17": "<p><span class='christ-shadow'>Child sacrifice, divination, sorcery — Israel gave itself to do evil. The final catalog echoes Manasseh&#x2019;s crimes (21:6) — the north doing what the worst southern king later does. The offering of children to Molech is the demonic inversion of the gospel: false religion demands the death of children; the gospel announces that God gives his Son so that children may live. &#x201C;God so loved the world that he gave his only Son, that whoever believes in him should not perish but have eternal life&#x201D; (John 3:16) — the anti-Molech statement of Scripture.</span></p>",
        "18": "<p><span class='christ-shadow'>YHWH extremely angry, expelled them from his sight; only Judah remained. The divine anger that expels — &#x201C;from his sight&#x201D; (<i>me-al panav</i>) — is the language of exile in the deepest sense: removed from divine presence. Jesus experiences this on the cross: &#x201C;My God, my God, why have you forsaken me?&#x201D; (Matt 27:46) — the ultimate expulsion from the divine face. Christ endures the &#x201C;expelled from his sight&#x201D; experience so that his people need not be permanently expelled from God&#x2019;s presence.</span></p>",
        "19": "<p><span class='christ-shadow'>Judah also did not obey — followed the practices Israel introduced. The northern infection spread south; the exile that fell on Israel will eventually fall on Judah too (586 BCE). Paul universalizes this: &#x201C;Both Jews and Greeks are under sin&#x201D; (Rom 3:9). The Deuteronomist shows the progressive failure of both kingdoms; Paul shows the universal condition. Christ is the answer to both: &#x201C;There is therefore now no condemnation for those who are in Christ Jesus&#x201D; (Rom 8:1) — the condemnation that fell on both Israel (721) and Judah (586) is absorbed by the one who was condemned so they need not be.</span></p>",
        "20": "<p><span class='christ-shadow'>YHWH rejected all the seed of Israel, afflicted them, gave them into the hand of raiders. The rejection language — <i>va-yim'as YHWH be-khol-zera Yisrael</i> (the LORD rejected all the seed of Israel) — is the culmination of the covenant lawsuit. But Paul argues that even this rejection is not the final word: &#x201C;Has God rejected his people? By no means!&#x201D; (Rom 11:1). The exile-rejection of ch17 generates the question of Romans 11; the answer is Christ through whom the rejected find ultimate acceptance.</span></p>",
        "21": "<p><span class='christ-shadow'>When Israel was torn from the house of David, Jeroboam led them away from following YHWH. The division of the kingdom is traced back to Jeroboam as its agent. The split between Israel and Judah is the political expression of covenant fragmentation — one people becoming two, the northern tribe separated from the Davidic throne. Christ reunites: &#x201C;For he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility&#x201D; (Eph 2:14). The north-south division that Jeroboam institutionalized, Christ overcomes in a deeper register.</span></p>",
        "22": "<p><span class='christ-shadow'>The Israelites continued in all of Jeroboam&#x2019;s sins — never turned away from them. The power of entrenched generational sin — never turning from it — is the exact diagnosis that only the new covenant addresses. Jer 31:34: &#x201C;No longer shall each one teach his neighbor and his brother, saying, &#x2018;Know the LORD,&#x2019; for they shall all know me&#x201D; — the knowledge of God that Israel pursued through covenant but never internalized becomes an accomplished reality through the Spirit Christ sends.</span></p>",
        "23": "<p><span class='christ-shadow'>The LORD removed Israel from his sight, as declared through all his servants the prophets. So Israel was exiled from their land to Assyria. The exile fulfills the prophetic word — every prophet who warned of exactly this outcome (Amos 5:27; Hos 9:3; Mic 1:6-9) is vindicated. The prophetic word that predicted exile is the same word that predicts restoration through the servant of Isaiah 40-55. Christ is the one through whom the prophetic word of restoration is fulfilled: &#x201C;Today this Scripture has been fulfilled in your hearing&#x201D; (Luke 4:21).</span></p>",
        "24": "<p><span class='christ-shadow'>The Assyrian king populates Samaria with Babylonians, Cutheans, and others — the origin of the Samaritans. The mixed population brought in to replace the exiled northern Israelites becomes the Samaritans of NT times. Jesus&#x2019;s encounter with the Samaritan woman (John 4) is the direct redemptive engagement with this history: the people produced by Israel&#x2019;s exile and Assyrian resettlement become recipients of the gospel precisely when Jesus sits at Jacob&#x2019;s well in Samaria.</span></p>",
        "25": "<p><span class='christ-shadow'>The newcomers do not fear YHWH; lions are sent among them. The lions as divine judgment on those who do not acknowledge the god of the land resonates with the broader theme: to inhabit the land without knowing its Lord brings destruction. Christ addresses the Samaritans&#x2019; incomplete knowledge directly in John 4:22: &#x201C;You worship what you do not know; we worship what we know, for salvation is from the Jews.&#x201D; The ignorance that invited lions in 2 Kings 17 is the same ignorance Jesus addresses in John 4 — with revelation rather than judgment.</span></p>",
        "26": "<p><span class='christ-shadow'>The king of Assyria is told the peoples don&#x2019;t know the requirements of the god of the land. The concept of a god whose &#x201C;requirements&#x201D; (<i>mishpat</i>) must be known to avoid disaster reflects ANE territorial deity theology. But YHWH is not a territorial deity; he is the Creator of all. Christ transcends territorial religion entirely: &#x201C;God so loved the world&#x201D; — not Israel alone, not Samaria alone, but the cosmos. The Assyrian king&#x2019;s pragmatic theology (learn the local god&#x2019;s rules) is vastly less than what Christ reveals about the God who seeks worshipers &#x201C;in spirit and truth.&#x201D;</span></p>",
        "27": "<p><span class='christ-shadow'>An exiled Israelite priest is sent back to Bethel to teach them. The compromise — an Israelite priest teaching pagan settlers at Bethel (the site of Jeroboam&#x2019;s calves) — produces syncretism rather than genuine covenant worship (v33). The inadequacy of religious instruction without heart transformation is the lesson. Christ sends the Spirit to produce genuine transformation: &#x201C;But the Helper, the Holy Spirit, whom the Father will send in my name, he will teach you all things&#x201D; (John 14:26). External religious instruction could not create what the Spirit produces internally.</span></p>",
        "28": "<p><span class='christ-shadow'>One priest returns to Bethel and teaches them to fear YHWH. The single returned priest teaching the Samaritans at Bethel is a pale foreshadowing of the twelve apostles sent to all nations. But the instruction produces mixed results (v33: they feared YHWH and served their own gods). Christ sends the Spirit precisely to go beyond instruction to transformation: &#x201C;Not because I desired a gift, but I desire fruit that may abound to your account&#x201D; (Phil 4:17). Instruction plants seeds; the Spirit produces fruit.</span></p>",
        "29": "<p><span class='christ-shadow'>Each national group made its own gods and placed them in the Samaritan shrines. The religious pluralism of the resettled Samaria — every group keeping its own deity while nominally acknowledging YHWH — is the syncretism that Jesus directly addresses in John 4:22. The Samaritan woman&#x2019;s &#x201C;you worship on this mountain&#x201D; and Jesus&#x2019;s response about spirit-and-truth worship cuts through the entire Samaritan-syncretic compromise. Christ replaces the many deities with one worship in one Spirit.</span></p>",
        "30": "<p><span class='christ-shadow'>Succoth-benoth (Babylonian), Nergal (Cuthean), Ashima (Hamathite) — the pantheon of resettled Samaria. The catalog of pagan deities installed in YHWH&#x2019;s land is the ultimate irony: the land promised to Abraham and conquered under Joshua now hosts Babylonian and Mesopotamian gods. Paul&#x2019;s Areopagus speech addresses the Athenian version of this: &#x201C;Whom therefore you ignorantly worship, him I declare to you&#x201D; (Acts 17:23). The unknown/multiple gods of the nations find their answer in the one God who has made himself known in Christ.</span></p>",
        "31": "<p><span class='christ-shadow'>The Avvites and Sepharvites worship Nibhaz, Tartak, Adrammelech, and Anammelech — including child sacrifice to the last two. The catalog of gods requiring child sacrifice appears on both sides of the exile: before (Manasseh&#x2019;s Molech worship in Judah, 21:6) and after (Sepharvite worship in resettled Samaria). The anti-type is Christ&#x2019;s proclamation &#x201C;Let the children come to me, and do not hinder them, for to such belongs the kingdom of heaven&#x201D; (Matt 19:14) — the children that false gods demanded as victims, Christ welcomes as heirs.</span></p>",
        "32": "<p><span class='christ-shadow'>They feared YHWH and appointed from their own ranks priests for the high places. The self-appointed priesthood — not Levitical, not according to the Torah — is the mark of the syncretistic system. Christ appoints his own priesthood not from human lineage but through the Spirit: &#x201C;You are a royal priesthood&#x201D; (1 Pet 2:9) — all believers constitute the priestly community, not through Levitical descent or self-appointment but through union with the great high priest.</span></p>",
        "33": "<p><span class='christ-shadow'>They worshipped YHWH and served their own gods. The double loyalty — YHWH and the national deities simultaneously — is the exact syncretism Jesus rules out: &#x201C;No one can serve two masters&#x201D; (Matt 6:24). The Samaritan compromise of v33 is the social form of the divided heart that Jesus diagnoses in the Sermon on the Mount. The exclusive claim of Christ (&#x201C;I am the way, the truth, and the life; no one comes to the Father except through me&#x201D; — John 14:6) ends the syncretistic option.</span></p>",
        "34": "<p><span class='christ-shadow'>To this day they follow their former practices — they do not truly fear YHWH. The narrator&#x2019;s &#x201C;to this day&#x201D; reflects the persistence of Samaritan syncretism into the author&#x2019;s present. The encounter of Jesus with the Samaritan woman in John 4 takes place in the context of precisely this ongoing religious compromise — which is why his offer of &#x201C;living water&#x201D; and &#x201C;worship in spirit and truth&#x201D; is so radical. Christ addresses not just an individual woman but the centuries-long failure that 2 Kings 17:34 documents.</span></p>",
        "35": "<p><span class='christ-shadow'>YHWH&#x2019;s covenant command: &#x201C;Do not worship other gods.&#x201D; The Deuteronomic monotheism that the resettled Samaritans violated is stated in its clearest form. Jesus recapitulates and centralizes this: &#x201C;Hear, O Israel: the Lord our God, the Lord is one. And you shall love the Lord your God with all your heart&#x201D; (Mark 12:29-30). The Shema that stands behind v35&#x2019;s prohibition is the commandment Christ calls the greatest — and which he himself perfectly embodied.</span></p>",
        "36": "<p><span class='christ-shadow'>Fear the LORD who brought you out of Egypt — he is the one to worship. The Exodus foundation of monotheism: YHWH&#x2019;s identity is defined by the great redemptive act of deliverance. Christ performs the greater Exodus (Luke 9:31 — Moses and Elijah discuss his <i>exodon</i>) delivering from a greater bondage than Egypt. The &#x201C;bow to him and offer sacrifices to him&#x201D; prescribed in v36 finds its NT form in &#x201C;present your bodies as a living sacrifice, holy and acceptable to God&#x201D; (Rom 12:1).</span></p>",
        "37": "<p><span class='christ-shadow'>&#x201C;Carefully observe forever the statutes and ordinances he wrote for you.&#x201D; The written Torah given at Sinai is the covenant standard the Samaritans did not follow. But the new covenant addresses the insufficiency of written law alone: &#x201C;I will put my law within them and write it on their hearts&#x201D; (Jer 31:33). Christ does not abolish the Torah (Matt 5:17) but writes it internally through the Spirit (2 Cor 3:3: &#x201C;written not with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts&#x201D;).</span></p>",
        "38": "<p><span class='christ-shadow'>&#x201C;Do not forget the covenant I have made with you.&#x201D; Covenant-forgetting is the root of Israel&#x2019;s and Samaria&#x2019;s failure. Hebrews addresses the danger of spiritual drift and forgetting to the church: &#x201C;Therefore we must pay much closer attention to what we have heard, lest we drift away from it&#x201D; (Heb 2:1). The warning against forgetting the covenant is renewed in the new covenant as a warning against neglecting so great a salvation (Heb 2:3).</span></p>",
        "39": "<p><span class='christ-shadow'>&#x201C;Fear only the LORD your God, and he will rescue you from all your enemies.&#x201D; The divine promise conditional on exclusive covenant loyalty — rescue in exchange for undivided fear. Christ makes the rescue unconditional through his own faithfulness: &#x201C;He has delivered us from the domain of darkness and transferred us to the kingdom of his beloved Son&#x201D; (Col 1:13). The conditional rescue of the covenant (if you fear him, he will rescue) becomes unconditional rescue through the Son who is perfectly faithful on behalf of those who are not.</span></p>",
        "40": "<p><span class='christ-shadow'>But they would not listen — they kept to their old ways. The finality of Samaritan covenant-refusal is stated simply. The old ways prove stronger than the instruction. This is precisely the point of Jeremiah&#x2019;s new covenant oracle (Jer 31:31-34): the old covenant failed not because it was defective but because the people could not keep it. The new covenant Christ mediates addresses the root: &#x201C;I will put my law within them&#x201D; — not as external instruction but as internal reality through the Spirit.</span></p>",
        "41": "<p><span class='christ-shadow'>So these peoples feared YHWH and served their own idols — their children and grandchildren do the same today. The persistence of Samaritan syncretism across generations — children and grandchildren maintaining the compromise — is the final word of ch17. Against this multigenerational persistence of mixed-worship, the gospel effects a permanent break: &#x201C;Old things have passed away; behold, all things have become new&#x201D; (2 Cor 5:17). The Samaritan woman at the well represents the living reality of what ch17 documents as dead tradition — and in John 4, Christ offers the living water that ends the multigenerational compromise.</span></p>"
    }
}

def main():
    existing = load_comm('mkt-christ', '2kings')
    merge_comm(existing, TWO_KINGS_CHRIST)
    save_comm('mkt-christ', '2kings', existing)
    il = json.loads((ROOT / 'data/interlinear/2kings.json').read_text())
    all_ok = True
    for ch in ['15', '16', '17']:
        got = set(existing.get(ch, {}).keys())
        need = set(il[ch].keys())
        missing = need - got
        if missing:
            print(f'  ch{ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch{ch}: {len(got)} verses complete')
    if all_ok:
        print('2 Kings christ fill (chs 15–17) done. All verses present.')

if __name__ == '__main__':
    main()
